import{_ as a}from"./plugin-vue_export-helper-c27b6911.js";import{r as e,o as t,c as p,a as s,b as o,d as l,e as c}from"./app-d263b1ce.js";const d={},i={href:"https://youtu.be/lwmwlA2WhFc?si=Szgl3bDlly7CF266",target:"_blank",rel:"noopener noreferrer"},r=c(`<p>서브쿼리(subquery)란 nested query 또는 inner query 라고 불리며<br> SELECT, INSERT, UPDATE, DELETE 쿼리문에 포함된 쿼리를 말한다.</p><p>서브쿼리는 쿼리문 내에서 괄호<code>()</code>안에 기술된다.</p><p>서브쿼리의 종류에는 IN, ANY, ALL, EXISTS 등이 있다.</p><table><thead><tr><th>이름</th><th>설명</th></tr></thead><tbody><tr><td>IN</td><td>결과중 하나라도 일치하면 TRUE</td></tr><tr><td>ANY</td><td>결과와 하나 이상 일치</td></tr><tr><td>ALL</td><td>결과와 모든 값이 일치</td></tr><tr><td>EXISTS</td><td>결과 중에서 값이 최소 하나라도 있으면 TRUE</td></tr><tr><td>NOT ~</td><td>결과의 값과 값이 다르다면 TRUE</td></tr></tbody></table><h2 id="예제-테이블" tabindex="-1"><a class="header-anchor" href="#예제-테이블" aria-hidden="true">#</a> 예제 테이블</h2><p><strong>Department</strong></p><table><thead><tr><th>id</th><th>name</th><th>leader_id</th></tr></thead></table><p><strong>Employee</strong></p><table><thead><tr><th>id</th><th>name</th><th>birth_date</th><th>sex</th><th>positon</th><th>salary</th><th>dept_id(department)</th></tr></thead></table><p><strong>Project</strong></p><table><thead><tr><th>id</th><th>name</th><th>leader_id</th><th>start_date</th><th>end_date</th></tr></thead></table><p><strong>Works_on</strong></p><table><thead><tr><th>empl_id(employee)</th><th>proj_id(project)</th></tr></thead></table><h2 id="select-with-subquery-예제" tabindex="-1"><a class="header-anchor" href="#select-with-subquery-예제" aria-hidden="true">#</a> SELECT with subquery 예제</h2><p><strong>예제1: ID가 14인 임직원보다 생일이 빠른 임직원의 ID, 이름, 생일을 알고 싶다.</strong></p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> birth_date <span class="token keyword">FROM</span> employee <span class="token keyword">WHERE</span> id <span class="token operator">=</span> <span class="token number">14</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> id<span class="token punctuation">,</span> name<span class="token punctuation">,</span> birth_date <span class="token keyword">FROM</span> employee <span class="token keyword">WHERE</span> birth_date <span class="token operator">&lt;</span> <span class="token string">&#39;1992-08-04&#39;</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>서브쿼리를 사용하지 않으면 두 개의 쿼리를 순차적으로 실행해서 결과를 찾아야한다.</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> id<span class="token punctuation">,</span> name<span class="token punctuation">,</span> birth_date 
<span class="token keyword">FROM</span> employee 
<span class="token keyword">WHERE</span> birth_date <span class="token operator">&lt;</span> <span class="token punctuation">(</span>
  <span class="token keyword">SELECT</span> birth_date <span class="token keyword">FROM</span> employee <span class="token keyword">WHERE</span> id <span class="token operator">=</span> <span class="token number">14</span>
  <span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>서브쿼리를 이용하면 두 개의 쿼리를 하나로 합쳐서 하나의 쿼리로 실행해 결과를 찾는다.</p><h3 id="in-사용-예제" tabindex="-1"><a class="header-anchor" href="#in-사용-예제" aria-hidden="true">#</a> IN 사용 예제</h3><p><strong>예제2: ID가 5인 임직원과 같은 프로젝트에 참여한 임직원들의 ID를 알고 싶다.</strong></p><p>ID가 5인 임직원의 프로젝트 id를 찾는 쿼리</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> proj_id <span class="token keyword">FROM</span> works_on <span class="token keyword">WHERE</span> empl_id <span class="token operator">=</span> <span class="token number">5</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>프로젝트 id가 2001, 2002이고 임직원 아이디가 5인 것을 제외한 임직원 아이디를 찾는 쿼리</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> <span class="token keyword">DISTINCT</span> empl_id <span class="token keyword">FROM</span> works_on <span class="token keyword">WHERE</span> empl_id <span class="token operator">!=</span> <span class="token number">5</span> <span class="token operator">AND</span> proj_id <span class="token operator">IN</span> <span class="token punctuation">(</span><span class="token number">2001</span><span class="token punctuation">,</span> <span class="token number">2002</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>이 두 쿼리를 하나의 쿼리로 정보를 찾을 수 있다.</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> <span class="token keyword">DISTINCT</span> empl_id <span class="token keyword">FROM</span> works_on <span class="token comment">-- outer 쿼리</span>
<span class="token keyword">WHERE</span> empl_id <span class="token operator">!=</span> <span class="token number">5</span> <span class="token operator">AND</span> proj_id <span class="token operator">IN</span> <span class="token punctuation">(</span>
  <span class="token keyword">SELECT</span> proj_id <span class="token keyword">FROM</span> works_on <span class="token keyword">WHERE</span> empl_id <span class="token operator">=</span> <span class="token number">5</span>
<span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>예제2-1: ID가 5인 임직원과 같은 프로젝트에 참여한 임직원들의 ID와 이름을 알고 싶다.</strong></p><p>위의 예제에서 쿼리 결과는 임직원들의 ID밖에 알 수 없다.<br> 그렇다면 id와 이름을 알 수 있는 방법은 works_on 테이블을 쿼리해서 나온 결과를 다시 employee 테이블에 쿼리하는 것이다.</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> id<span class="token punctuation">,</span> name
<span class="token keyword">FROM</span> employee<span class="token punctuation">,</span>
  <span class="token punctuation">(</span>
    <span class="token keyword">SELECT</span> <span class="token keyword">DISTINCT</span> empl_id <span class="token keyword">FROM</span> works_on <span class="token comment">-- 예제 2의 쿼리</span>
    <span class="token keyword">WHERE</span> empl_id <span class="token operator">!=</span> <span class="token number">5</span> <span class="token operator">AND</span> proj_id <span class="token operator">IN</span> <span class="token punctuation">(</span>
      <span class="token keyword">SELECT</span> proj_id <span class="token keyword">FROM</span> works_on <span class="token keyword">WHERE</span> empl_id <span class="token operator">=</span> <span class="token number">5</span>
    <span class="token punctuation">)</span>
  <span class="token punctuation">)</span> <span class="token keyword">AS</span> DSTNCT_E
<span class="token keyword">WHERE</span> id <span class="token operator">=</span> DSTNCT_E<span class="token punctuation">.</span>empl_id<span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="exists-사용-예제" tabindex="-1"><a class="header-anchor" href="#exists-사용-예제" aria-hidden="true">#</a> EXISTS 사용 예제</h3><p><strong>예제3: ID가 7 혹은 12인 임직원이 참여한 프로젝트의 ID와 이름을 알고 싶다.</strong></p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> P<span class="token punctuation">.</span>id<span class="token punctuation">,</span> P<span class="token punctuation">.</span>name
<span class="token keyword">FROM</span> project <span class="token keyword">AS</span> P
<span class="token keyword">WHERE</span> <span class="token keyword">EXISTS</span> <span class="token punctuation">(</span>
  <span class="token keyword">SELECT</span> <span class="token operator">*</span>
  <span class="token keyword">FROM</span> works_on <span class="token keyword">AS</span> W
  <span class="token keyword">WHERE</span> W<span class="token punctuation">.</span>proj_id <span class="token operator">=</span> P<span class="token punctuation">.</span>id <span class="token operator">AND</span> W<span class="token punctuation">.</span>empl_id <span class="token operator">IN</span> <span class="token punctuation">(</span><span class="token number">7</span><span class="token punctuation">,</span> <span class="token number">12</span><span class="token punctuation">)</span>
<span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>서브쿼리에 있는 <code>W.proj_id = P.id</code>에서 P.id는 outer 쿼리에있는 project의 단축어인 P이다.<br> 서브쿼리가 바깥쪽 query의 attribute를 참조할 때, 상관 서브쿼리(correlated subquery)라고 부른다.</p><p>또 다른 방법으로 EXISTS가 있는 부분을 IN으로 바꿔줄 수도 있다.</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> P<span class="token punctuation">.</span>id<span class="token punctuation">,</span> P<span class="token punctuation">.</span>name
<span class="token keyword">FROM</span> project <span class="token keyword">AS</span> P
<span class="token keyword">WHERE</span> id <span class="token operator">IN</span> <span class="token punctuation">(</span> <span class="token comment">-- EXISTS를 IN으로 변경</span>
  <span class="token keyword">SELECT</span> W<span class="token punctuation">.</span>proj_id
  <span class="token keyword">FROM</span> works_on <span class="token keyword">AS</span> W
  <span class="token keyword">WHERE</span> W<span class="token punctuation">.</span>empl_id <span class="token operator">IN</span> <span class="token punctuation">(</span><span class="token number">7</span><span class="token punctuation">,</span> <span class="token number">12</span><span class="token punctuation">)</span>
<span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>위의 두 개의 쿼리문은 같은 결과를 반환한다.<br> 이렇게 EXISTS와 IN은 바꿔서 사용할 수 있다.</p><h3 id="not-exists-사용-예제" tabindex="-1"><a class="header-anchor" href="#not-exists-사용-예제" aria-hidden="true">#</a> NOT EXISTS 사용 예제</h3><p>NOT EXISTS는 서브쿼리의 결과가 단 하나의 row도 없다면 TRUE를 반환한다.</p><p><strong>예제4: 2000년대생이 없는 부서의 ID와 이름을 알고 싶다.</strong></p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> D<span class="token punctuation">.</span>id<span class="token punctuation">,</span> D<span class="token punctuation">.</span>name
<span class="token keyword">FROM</span> department <span class="token keyword">AS</span> D
<span class="token keyword">WHERE</span> <span class="token operator">NOT</span> <span class="token keyword">EXISTS</span> <span class="token punctuation">(</span>
  <span class="token keyword">SELECT</span> <span class="token operator">*</span>
  <span class="token keyword">FROM</span> employee <span class="token keyword">AS</span> E
  <span class="token keyword">WHERE</span> E<span class="token punctuation">.</span>dept_id <span class="token operator">=</span> D<span class="token punctuation">.</span>id <span class="token operator">AND</span> E<span class="token punctuation">.</span>birth_date <span class="token operator">&gt;=</span> <span class="token string">&#39;2000-01-01&#39;</span>
<span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>이 쿼리문도 마찬가지로 NOT IN으로 바꿀 수 있다.</p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> D<span class="token punctuation">.</span>id<span class="token punctuation">,</span> D<span class="token punctuation">.</span>name
<span class="token keyword">FROM</span> department <span class="token keyword">AS</span> D
<span class="token keyword">WHERE</span> D<span class="token punctuation">.</span>id <span class="token operator">NOT</span> <span class="token operator">IN</span> <span class="token punctuation">(</span>
  <span class="token keyword">SELECT</span> E<span class="token punctuation">.</span>dept_id
  <span class="token keyword">FROM</span> employee <span class="token keyword">AS</span> E
  <span class="token keyword">WHERE</span> E<span class="token punctuation">.</span>birth_date <span class="token operator">&gt;=</span> <span class="token string">&#39;2000-01-01&#39;</span>
<span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="any-사용-예제" tabindex="-1"><a class="header-anchor" href="#any-사용-예제" aria-hidden="true">#</a> ANY 사용 예제</h3><p><strong>예제5: 리더보다 높은 연봉을 받는 부서원을 가진 리더의 ID와 이름, 연봉을 알고 싶다.</strong></p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> E<span class="token punctuation">.</span>id<span class="token punctuation">,</span> E<span class="token punctuation">.</span>name<span class="token punctuation">,</span> E<span class="token punctuation">.</span>salary
<span class="token keyword">FROM</span> department <span class="token keyword">AS</span> D<span class="token punctuation">,</span> employee <span class="token keyword">AS</span> E
<span class="token keyword">WHERE</span> D<span class="token punctuation">.</span>leader_id <span class="token operator">AND</span> E<span class="token punctuation">.</span>salary <span class="token operator">&lt;</span> <span class="token keyword">ANY</span><span class="token punctuation">(</span> <span class="token comment">-- ANY는 비교연산자와 함께 사용, 단 하나라도 True라면 True</span>
  <span class="token keyword">SELECT</span> salary
  <span class="token keyword">FROM</span> employee
  <span class="token keyword">WHERE</span> id <span class="token operator">&lt;&gt;</span> D<span class="token punctuation">.</span>leader_id <span class="token operator">AND</span> dept_id <span class="token operator">=</span> E<span class="token punctuation">.</span>dept_id <span class="token comment">-- &lt;&gt; 연산자는 != 연산자와 같다</span>
<span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="all-사용-예제" tabindex="-1"><a class="header-anchor" href="#all-사용-예제" aria-hidden="true">#</a> ALL 사용 예제</h3><p><strong>예제5: ID가 13인 임직원과 한번도 같은 프로젝트에 참여하지 못한 임직원들의 ID,이름,직군을 알고 싶다.</strong></p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token keyword">SELECT</span> <span class="token keyword">DISTINCT</span> E<span class="token punctuation">.</span>id<span class="token punctuation">,</span> E<span class="token punctuation">.</span>name<span class="token punctuation">,</span> E<span class="token punctuation">.</span>position
<span class="token keyword">FROM</span> employee <span class="token keyword">AS</span> E<span class="token punctuation">,</span> works_on <span class="token keyword">AS</span> W
<span class="token keyword">WHERE</span> E<span class="token punctuation">.</span>id <span class="token operator">=</span> W<span class="token punctuation">.</span>empl_id <span class="token operator">AND</span> W<span class="token punctuation">.</span>proj_id <span class="token operator">&lt;&gt;</span> <span class="token keyword">ALL</span><span class="token punctuation">(</span> <span class="token comment">-- 비교 연산이 모두 True라면 True를 반환</span>
  <span class="token keyword">SELECT</span> proj_id
  <span class="token keyword">FROM</span> works_on
  <span class="token keyword">WHERE</span> empl_id <span class="token operator">=</span> <span class="token number">13</span>
<span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="in-vs-exists" tabindex="-1"><a class="header-anchor" href="#in-vs-exists" aria-hidden="true">#</a> IN vs EXISTS</h2><p>RDBMS의 종류와 버전에 따라 다르며 최근 버전은 많은 개선이 이루어져 IN과 EXISTS의 성능 차이가 거의 없다.</p>`,52);function u(k,m){const n=e("ExternalLinkIcon");return t(),p("div",null,[s("blockquote",null,[s("p",null,[s("a",i,[o("https://youtu.be/lwmwlA2WhFc?si=Szgl3bDlly7CF266"),l(n)])])]),r])}const E=a(d,[["render",u],["__file","sql-subquery.html.vue"]]);export{E as default};
